frame_eqs:
decay=1;
zoom=1;
wave_a=0;
warp=0;

q6=aspecty;


t1=t1+.05/fps;
t1=t1*below(t1,2);
q1=t1;
t2=t2+.03/fps;
t2=t2*below(t2,2);
q2=t2;
t3=t3+.07/fps;
t3=t3*below(t3,2);
q3=t3;
decay = 1;

//uncommenting this block will make decay start at 0 when preset begins, and rise to the "max_decay" value
//max_decay = 0.97;
//dcsp = dcsp + 0.007*(75/fps);
//dcsp = min(dcsp , max_decay);
//decay = dcsp;

//volume, and volume based time. framerate adjusted
vol = (bass+mid+treb)*0.25;
vol = vol*vol;

mtime = mtime + vol * 0.01 * (75/fps);

q1 = vol;
q2 = mtime;

//non bass volume
vol2 = (mid+treb)*0.33;
vol2 = vol2*vol2;

m2time = m2time + vol2 * 0.01 * (75/fps);

q3 = vol2;
q4 = m2time;


//krash's beat detection code
volume = 0.3*(bass+mid+att);
beatrate = equal(beatrate,0) + (1-equal(beatrate,0))*(below(volume,0.01) + (1-below(volume,0.01))*beatrate);
lastbeat = lastbeat + equal(lastbeat,0)*time;
meanbass_att = 0.1*(meanbass_att*9 + bass_att);
peakbass_att = max(bass_att,peakbass_att);
beatrate = max(if(beat,if(below(time-lastbeat,2*beatrate),0.1*(beatrate*9 + time - lastbeat),beatrate),beatrate),0.1);
peakbass_att = beat*bass_att + (1-beat)*peakbass_att*(above(time - lastbeat, 2*beatrate)*0.95 + (1-above(time - lastbeat, 2*beatrate))*0.995);
lastbeat = beat*time + (1-beat)*lastbeat;
peakbass_att = max(peakbass_att,1.1*meanbass_att);
beat = above(volume,0.8)*below(peakbass_att - bass_att, 0.05*peakbass_att)*above(time - lastbeat, 0.1 + 0.5*(beatrate - 0.1));
beatcounter = beatcounter + beat;
mode = if(beat*equal(beatcounter%2,0),1-mode,mode);
flip = 2*mode-1;

beatdrop = if( equal(beatdrop,0) , beat , max(beatdrop - 0.02*(75/fps) , 0) );

q7 = beatdrop;
q8 = flip;




q6 = 1.0 + 0.005;//beatdrop*0.03;

zoom = 1;
sx = -q6;
sy = q6;

warp=0;

//dx = sin(time/4)*0.15;
cx = 0.5 + dx ;

gamma = 1 + beatdrop*beatdrop;
q29=vol*8;

wave_0_per_frame:
h=q5;
s = 0.7;
l= 0.8;
///////////////////////////////////////////////////////////////////////////////////////////////
//
//                            HSL to RGB by PieturP
//
// hue         h ( 0 - 0.9 )                          rr ( 0 - 1 )
// saturation  s ( 0 - 1 )            - >             gg ( 0 - 1 )
// luminance   l ( 0 - 1 )                            bb ( 0 - 1 )
//
cc=(6*h);
cc=if(below(cc,1),0,if(below(cc,2),1,if(below(cc,3),2,if(below(cc,4),3,if(below(cc,5),4,5)))));
zf=(6*h)-cc;
zm=l;
zp=l*(1-s);
zq=l*(1-s*zf);
zt=l*(1-s*(1-zf));
monitor=zq;
rr=if(equal(cc,0),zm,if(equal(cc,1),zq,if(equal(cc,2),zp,if(equal(cc,3),zp,if(equal(cc,4),zt,zm)))));
gg=if(equal(cc,0),zt,if(equal(cc,1),zm,if(equal(cc,2),zm,if(equal(cc,3),zq,if(equal(cc,4),zp,zp)))));
bb=if(equal(cc,0),zp,if(equal(cc,1),zp,if(equal(cc,2),zt,if(equal(cc,3),zm,if(equal(cc,4),zm,zq)))));
rr=if(equal(s,0),l,rr);
gg=if(equal(s,0),l,gg);
bb=if(equal(s,0),l,bb);

///////////////////////////////////////////////////////////////////////////////////////////////
r=rr;
g=gg;
b=bb;

wave_0_per_point:
n=sample*6.283;
phs=-sample * 0.2;
tm=q4 + phs*4;

flip=flip+1;
flip=flip*below(flip,2);

xp=0;
yp=(flip*0.05-0.025)*(sample);
zp=0;

//spin;
ang=0;//tm*20 + sin(tm*76 + time*4)*0.4;
sa=sin(ang);ca=cos(ang);
xr=xp*sa + yp*ca;
yr=xp*ca - yp*sa;
zr=zp;

xp=xr;
yp=yr + 0.05 + (sin(tm)*0.5 + 0.5)*0.2 + 0.05;
zp=zr;

//wrist movement;
ang=0.5*(sin(tm*9)+sin(tm*3.248));

xq=xp;
sa=sin(ang);ca=cos(ang);
yq=yp*sa + zp*ca;
zq=yp*ca - zp*sa;


ang=tm*8;
sa=sin(ang);ca=cos(ang);
xp=xq*sa + yq*ca;
yp=xq*ca - yq*sa;
zp=zq;

//forearm movement;
zp=zp-0.3;
ang=3.14 + (sin(tm*2 - 0.5)+sin(tm*1.237))*1.25;
xq=xp;
sa=sin(ang);ca=cos(ang);
yq=yp*sa + zp*ca;
zq=yp*ca - zp*sa;

//upper arm twist
ang=-1.0 + cos(tm*3 + 0.5);
xp=xq*sa + yq*ca;
yp=xq*ca - yq*sa;
zp=zq;

//upper arm outward;
zp=zp-0.35;
ang=(cos(tm*1)+cos(tm*0.653))*0.875 - 1.05;
sa=sin(ang);ca=cos(ang);
xq=xp*sa + zp*ca;
yq=yp;
zq=xp*ca - zp*sa;

//upper arm up down;
ang=0.5*(cos(tm*1.273)+cos(tm));
xp=xq;
sa=sin(ang);ca=cos(ang);
yp=yq*ca - zq*sa;
zp=yq*sa + zq*ca;

//xp=xq;yp=yq;zp=zq;


//project into screenspace and draw on screen
zp=zp+1.5;
xs=xp/zp;
ys=yp/zp;

x=xs+0.5;
y=ys*1.3+0.5;


a=(1-sample);

